import { Metadata } from 'next'
import Link from 'next/link'
import { getAllArticles } from '@/lib/content'
import { Tag, Hash } from 'lucide-react'
import { SectionParticles } from '@/components/shared/section-particles'

export const metadata: Metadata = {
  title: 'Tags',
  description: 'Tất cả tags trên MAIY Tech Hub.',
}

export default async function TagsPage() {
  const articles = await getAllArticles()

  const tagMap = new Map<string, number>()
  articles.forEach((a) => {
    a.tags.forEach((tag) => {
      tagMap.set(tag, (tagMap.get(tag) || 0) + 1)
    })
  })

  const tags = Array.from(tagMap.entries()).sort((a, b) => b[1] - a[1])

  const tagColors = [
    { bg: 'hover:bg-blue-500/20', border: 'border-blue-500/25', text: 'text-blue-400', icon: '#3b82f6', glow: 'shadow-blue-500/20' },
    { bg: 'hover:bg-violet-500/20', border: 'border-violet-500/25', text: 'text-violet-400', icon: '#7c3aed', glow: 'shadow-violet-500/20' },
    { bg: 'hover:bg-emerald-500/20', border: 'border-emerald-500/25', text: 'text-emerald-400', icon: '#10b981', glow: 'shadow-emerald-500/20' },
    { bg: 'hover:bg-amber-500/20', border: 'border-amber-500/25', text: 'text-amber-400', icon: '#f59e0b', glow: 'shadow-amber-500/20' },
    { bg: 'hover:bg-pink-500/20', border: 'border-pink-500/25', text: 'text-pink-400', icon: '#ec4899', glow: 'shadow-pink-500/20' },
    { bg: 'hover:bg-cyan-500/20', border: 'border-cyan-500/25', text: 'text-cyan-400', icon: '#06b6d4', glow: 'shadow-cyan-500/20' },
    { bg: 'hover:bg-red-500/20', border: 'border-red-500/25', text: 'text-red-400', icon: '#ef4444', glow: 'shadow-red-500/20' },
    { bg: 'hover:bg-orange-500/20', border: 'border-orange-500/25', text: 'text-orange-400', icon: '#f97316', glow: 'shadow-orange-500/20' },
  ]

  return (
    <div className="min-h-screen relative overflow-hidden">
      {/* Deep space background — no dividers */}
      <div className="fixed inset-0 pointer-events-none">
        {/* Nebula gradients */}
        <div className="absolute top-0 right-0 w-[700px] h-[700px] rounded-full bg-violet-600/[0.04] blur-[120px]" />
        <div className="absolute top-1/3 left-0 w-[600px] h-[600px] rounded-full bg-blue-600/[0.04] blur-[120px]" />
        <div className="absolute bottom-0 right-1/4 w-[500px] h-[500px] rounded-full bg-pink-600/[0.03] blur-[120px]" />
        <div className="absolute top-2/3 left-1/3 w-[400px] h-[400px] rounded-full bg-cyan-600/[0.03] blur-[100px]" />
      </div>

      {/* Floating particles */}
      <SectionParticles color="rgba(255, 255, 255, 0.12)" count={30} />

      {/* Header */}
      <div className="relative pt-20 pb-16 px-6 md:px-12">
        <div className="max-w-5xl mx-auto">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-violet-500 to-blue-500 flex items-center justify-center shadow-lg shadow-violet-500/30">
              <Hash className="h-5 w-5 text-white" />
            </div>
            <span className="text-xs font-bold uppercase tracking-[0.2em] text-white/20">Khám phá</span>
          </div>
          <h1 className="text-5xl md:text-6xl font-black tracking-tight mb-4">
            <span className="bg-gradient-to-r from-violet-300 via-purple-300 to-blue-300 bg-clip-text text-transparent">
              Tags
            </span>
          </h1>
          <p className="text-white/30 text-base">
            {tags.length} tags · {articles.length} bài viết · lơ lửng trong không gian
          </p>
        </div>
      </div>

      {/* Floating tag cloud */}
      <div className="relative px-6 md:px-12 pb-16">
        <div className="max-w-5xl mx-auto">
          <div className="flex flex-wrap gap-3">
            {tags.map(([tag, count], i) => {
              const color = tagColors[i % tagColors.length]
              return (
                <Link
                  key={tag}
                  href={`/search?q=${encodeURIComponent(tag)}`}
                  className={`
                    group relative inline-flex items-center gap-2.5 px-5 py-3 rounded-2xl
                    border backdrop-blur-sm
                    transition-all duration-500 hover:-translate-y-1.5
                    hover:shadow-xl ${color.glow}
                    ${color.border}
                    bg-black/20 hover:bg-black/40
                  `}
                  style={{ boxShadow: `0 0 20px ${color.icon}08` }}
                >
                  <Tag
                    className="h-4 w-4 transition-transform duration-300 group-hover:scale-125 group-hover:rotate-12"
                    style={{ color: color.icon }}
                  />
                  <span className="text-sm font-semibold" style={{ color: color.icon }}>
                    {tag}
                  </span>
                  <span
                    className="px-2 py-0.5 rounded-full text-[10px] font-black"
                    style={{ backgroundColor: color.icon + '15', color: color.icon }}
                  >
                    {count}
                  </span>
                </Link>
              )
            })}
          </div>
        </div>
      </div>

      {/* Popular tags — floating cards */}
      {tags.length > 0 && (
        <div className="relative px-6 md:px-12 pb-20">
          <div className="max-w-5xl mx-auto">
            <h2 className="text-sm font-bold uppercase tracking-[0.2em] text-white/15 mb-6">
              Phổ biến nhất
            </h2>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {tags.slice(0, 9).map(([tag, count], i) => {
                const color = tagColors[i % tagColors.length]
                return (
                  <Link
                    key={tag}
                    href={`/search?q=${encodeURIComponent(tag)}`}
                    className={`
                      group relative flex items-center justify-between p-5 rounded-2xl
                      border backdrop-blur-sm
                      transition-all duration-500 hover:-translate-y-2 hover:shadow-2xl
                      ${color.border} ${color.glow}
                      bg-black/20 hover:bg-black/40
                    `}
                  >
                    {/* Subtle glow orb */}
                    <div
                      className="absolute -top-4 -right-4 w-20 h-20 rounded-full opacity-10 blur-2xl pointer-events-none transition-opacity duration-500 group-hover:opacity-20"
                      style={{ background: `radial-gradient(circle, ${color.icon}, transparent)` }}
                    />

                    <div className="flex items-center gap-4 relative">
                      <div
                        className="w-12 h-12 rounded-2xl flex items-center justify-center backdrop-blur-sm flex-shrink-0"
                        style={{ backgroundColor: color.icon + '15', border: `1px solid ${color.icon}30` }}
                      >
                        <Tag className="h-5 w-5" style={{ color: color.icon }} />
                      </div>
                      <div>
                        <p className="font-bold text-sm" style={{ color: color.icon }}>{tag}</p>
                        <p className="text-xs text-white/25">{count} bài viết</p>
                      </div>
                    </div>

                    <div
                      className="w-9 h-9 rounded-full flex items-center justify-center text-xs font-black flex-shrink-0"
                      style={{ backgroundColor: color.icon + '12', color: color.icon, border: `1px solid ${color.icon}20` }}
                    >
                      {i + 1}
                    </div>
                  </Link>
                )
              })}
            </div>
          </div>
        </div>
      )}

      {/* Empty state */}
      {tags.length === 0 && (
        <div className="relative px-6 pb-20 text-center">
          <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-white/[0.02] border border-white/[0.06] mb-6">
            <Tag className="h-10 w-10 text-white/[0.08]" />
          </div>
          <p className="text-white/20 text-lg font-medium mb-2">Chưa có tags nào</p>
          <p className="text-white/10 text-sm">Bài viết đầu tiên sẽ tạo tags tự động.</p>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useRef } from 'react'

interface Bubble {
  x: number
  y: number
  size: number
  opacity: number
  speed: number
  dx: number
  dy: number
}

interface SectionParticlesProps {
  /** CSS color for bubbles, e.g. 'rgba(139, 92, 246, 0.3)' */
  color?: string
  count?: number
  className?: string
}

export function SectionParticles({
  color = 'rgba(139, 92, 246, 0.25)',
  count = 20,
  className = '',
}: SectionParticlesProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    let raf: number
    let bubbles: Bubble[] = []

    const resize = () => {
      if (!canvas) return
      canvas.width = canvas.offsetWidth
      canvas.height = canvas.offsetHeight
    }

    const initBubbles = () => {
      bubbles = Array.from({ length: count }, () => ({
        x: Math.random() * (canvas?.width ?? 800),
        y: Math.random() * (canvas?.height ?? 400),
        size: Math.random() * 6 + 2,
        opacity: Math.random() * 0.3 + 0.05,
        speed: Math.random() * 0.4 + 0.1,
        dx: (Math.random() - 0.5) * 0.3,
        dy: -(Math.random() * 0.5 + 0.1),
      }))
    }

    const draw = () => {
      if (!canvas || !ctx) return
      ctx.clearRect(0, 0, canvas.width, canvas.height)

      bubbles.forEach((b) => {
        // Move
        b.x += b.dx
        b.y += b.dy

        // Wrap edges
        if (b.y < -b.size) {
          b.y = canvas.height + b.size
          b.x = Math.random() * canvas.width
        }
        if (b.x < -b.size) b.x = canvas.width + b.size
        if (b.x > canvas.width + b.size) b.x = -b.size

        // Draw bubble
        ctx.beginPath()
        ctx.arc(b.x, b.y, b.size, 0, Math.PI * 2)
        ctx.fillStyle = color.replace(/[\d.]+\)$/, `${b.opacity})`)
        ctx.fill()

        // Highlight dot (top-left shine)
        ctx.beginPath()
        ctx.arc(b.x - b.size * 0.25, b.y - b.size * 0.25, b.size * 0.25, 0, Math.PI * 2)
        ctx.fillStyle = `rgba(255, 255, 255, ${b.opacity * 0.8})`
        ctx.fill()
      })

      raf = requestAnimationFrame(draw)
    }

    const observer = new ResizeObserver(() => {
      resize()
    })
    observer.observe(canvas)
    resize()
    initBubbles()
    draw()

    return () => {
      cancelAnimationFrame(raf)
      observer.disconnect()
    }
  }, [color, count])

  return (
    <canvas
      ref={canvasRef}
      className={`absolute inset-0 w-full h-full pointer-events-none ${className}`}
      style={{ overflow: 'hidden' }}
    />
  )
}

